import { Check, X, Scissors } from "lucide-react";
import { SERVICES } from "../constants";

export default function FormPanel({ form, setForm, editing, onSubmit, onCancel }) {
  const handleChange = (field) => (e) =>
    setForm((prev) => ({ ...prev, [field]: e.target.value }));

  return (
    /* CONTAINER CENTRALIZADOR: Ocupa a tela toda para centralizar o card */
    <div style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '80vh',
      padding: '20px'
    }}>

      {/* O CARD DO FORMULÁRIO */}
      <aside className="pb-sidebar" style={{
        width: '100%',
        maxWidth: '400px', // Deixa pequeno como uma tela de login
        position: 'relative',
        zIndex: 5,
        padding: '40px',
        borderRadius: '0', // Estilo reto da barbearia
        boxShadow: '0 20px 50px rgb(253, 253, 253)',

        /* O FUNDO IGUAL A LANDING PAGE */
        backgroundImage: 'linear-gradient(rgba(245, 245, 220, 0.9), rgba(245, 245, 220, 0.9)), url("https://images.unsplash.com/photo-1599351431613-18ef1fdd27e1?q=80&w=688&auto=format&fit=crop")',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        border: '1px solid var(--amarelo)'
      }}>

        <p className="pb-section-label" style={{ justifyContent: 'center', marginBottom: '20px' }}>
          <Scissors size={14} style={{ marginRight: '8px' }} />
          Sistema de Agendamento
        </p>

        <h2 className="pb-form-title" style={{ textAlign: 'center', fontSize: '24px', marginBottom: '30px' }}>
          {editing ? (
            <>
              Editar Registro
              <span className="edit-badge" style={{ display: 'block', marginTop: '5px' }}>editando</span>
            </>
          ) : (
            "Faça seu Agendamento"
          )}
        </h2>

        <div className="pb-field" style={{ marginBottom: '20px' }}>
          <label className="pb-label">Nome Completo</label>
          <input
            className="pb-input"
            placeholder="Seu nome aqui"
            value={form.name}
            onChange={handleChange("name")}
            style={{ background: 'white' }}
          />
        </div>

        <div className="pb-field" style={{ marginBottom: '20px' }}>
          <label className="pb-label">Serviço Desejado</label>
          <select
            className="pb-select"
            value={form.service}
            onChange={handleChange("service")}
            style={{ background: 'white' }}
          >
            <option value="">Selecione um serviço</option>
            {SERVICES.map((s) => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </div>

        <div className="pb-field" style={{ marginBottom: '30px' }}>
          <label className="pb-label">Data &amp; Hora</label>
          <div className="pb-date-row" style={{ display: 'flex', gap: '10px' }}>
            <input
              className="pb-input"
              type="date"
              value={form.date}
              onChange={handleChange("date")}
              style={{ background: 'white' }}
            />
            <input
              className="pb-input"
              type="time"
              value={form.time}
              onChange={handleChange("time")}
              style={{ background: 'white' }}
            />
          </div>
        </div>

        <button
          className={`pb-btn-primary${editing ? " edit" : ""}`}
          onClick={onSubmit}
          style={{ width: '100%', padding: '15px', fontWeight: 'bold' }}
        >
          {editing && <Check size={14} style={{ marginRight: '8px' }} />}
          {editing ? "SALVAR ALTERAÇÕES" : "CONFIRMAR AGENDAMENTO"}
        </button>

        {editing && (
          <button 
            className="pb-btn-cancel" 
            onClick={onCancel}
            style={{ width: '100%', marginTop: '15px', background: 'transparent', border: 'none', color: '#666' }}
          >
            <X size={11} />
            Cancelar edição
          </button>
        )}
      </aside>
    </div>
  );
}
